function LFightIdleBubbleCtrl:LFightIdleBubbleCtrl()
	self._talkIntervalMin = 60
	self._talkIntervalMax = 100
	self._talkStayTime = 3

	self._nextCheckTime = 0
	self._checkInterval = 2

	self._bubbleRandTime = nil

	self._lastBubbleTime = nil
end

function LFightIdleBubbleCtrl:InitBubble(talkIntervalMin,talkIntervalMax,talkStayTime, monTalkIntervalMin, montTalkIntervalMax, monTalkStayTime)
	self._talkIntervalMin = talkIntervalMin
	self._talkIntervalMax = talkIntervalMax
	self._talkStayTime = talkStayTime

	self._monTalkIntervalMin = monTalkIntervalMin or 60
	self._monTalkIntervalMax = montTalkIntervalMax or 100
	self._monTalkStayTime = monTalkStayTime or 3
end

function LFightIdleBubbleCtrl:SetHeroTalkBubble(heroTalkTime , heroTalkIntervalMin, heroTalkIntervalMax)
	self._heroTalkTime = heroTalkTime
	self._heroTalkIntervalMin = heroTalkIntervalMin
	self._heroTalkIntervalMax = heroTalkIntervalMax
end

function LFightIdleBubbleCtrl:OnRun(time)
	local nextCheckTime = self._nextCheckTime
	if nextCheckTime < time then
		self._nextCheckTime = nextCheckTime + self._checkInterval
		self:CheckBubbleShow(time)
	end
end

function LFightIdleBubbleCtrl:CheckBubbleShow(time)
	local lastBubbleTime = self._lastBubbleTime
	if not lastBubbleTime then
		lastBubbleTime = {}
		self._lastBubbleTime = lastBubbleTime
		lastBubbleTime[0] = gModelInstance:GetLastBubbleTime(0) or 0
		lastBubbleTime[1] = gModelInstance:GetLastBubbleTime(1) or 0
		lastBubbleTime[2] = gModelInstance:GetLastBubbleTime(2) or self._heroTalkTime
	end
	local bubbleRandTime = self._bubbleRandTime
	if not bubbleRandTime then
		bubbleRandTime = {}
		self._bubbleRandTime = bubbleRandTime
		bubbleRandTime[0] = self:RandBubbleTime(0)
		bubbleRandTime[1] = self:RandBubbleTime(1)
		bubbleRandTime[2] = 0
	end
	-- 【G挂机冒险】移除冒险管家气泡功能
	-- local list = {0, 1}
	-- for k,bubbleType in ipairs(list) do
		local bubbleType = 2
		if lastBubbleTime[bubbleType] + bubbleRandTime[bubbleType] < time then
			if self:ShowBubble(bubbleType) then
				self._bubbleRandTime[bubbleType] = self:RandBubbleTime(bubbleType)
				self._lastBubbleTime[bubbleType] = time
				gModelInstance:SetLastBubbletime(bubbleType, time)
			end
		end
	-- end
end

