function LFightIdleBubbleCtrl:RandBubbleTime(bubbleType)
	if bubbleType == 0 then
		return LFightIdleConst.RandIntegerBetween(self._talkIntervalMin,self._talkIntervalMax)
	elseif bubbleType == 1 then
		return LFightIdleConst.RandIntegerBetween(self._monTalkIntervalMin,self._monTalkIntervalMax)
	elseif bubbleType == 2 then
		return LFightIdleConst.RandIntegerBetween(self._heroTalkIntervalMin,self._heroTalkIntervalMax)
	end
	return 0
end
